// deviceTypeIcon returns the appropriate lucide icon for the device type.
func deviceTypeIcon(deviceType string) templ.Component {
	switch deviceType {
	case "desktop":
		return icons.Monitor(icons.WithSize(16))
	case "mobile":
		return icons.Smartphone(icons.WithSize(16))
	case "tablet":
		return icons.Tablet(icons.WithSize(16))
	default:
		return icons.Globe(icons.WithSize(16))
	}
}

// deviceOSBrowser returns a combined "OS / Browser" string for display.
func deviceOSBrowser(d *device.Device) string {
	if d.OS != "" && d.Browser != "" {
		return d.OS + " / " + d.Browser
	}
	if d.OS != "" {
		return d.OS
	}
	if d.Browser != "" {
		return d.Browser
	}
	return "-"
}

